import numpy as np

def select_next_node(current_node, truck_nodes, depot_node, unvisited_nodes, distance_matrix):
    next_node = None

    if len(unvisited_nodes) == 0:
        next_node = depot_node
    else:
        min_dist = np.inf
        for node in unvisited_nodes:
            dist_to_node = distance_matrix[current_node][node]
            wait_time = dist_to_node * 0.1 # Adjust the wait time dynamically based on distance

            for truck_node in truck_nodes:
                dist_to_truck_node = distance_matrix[node][truck_node]
                wait_time += dist_to_truck_node * 0.1

            if wait_time < min_dist:
                min_dist = wait_time
                next_node = node

    return next_node
